package cache

import (
	"path/filepath"
	"strings"
	"testing"
	"time"
)

func TestPathUsesFullSHA256Digest(t *testing.T) {
	s := New(t.TempDir(), time.Minute)
	path := s.path("namecheap.domains.check?DomainList=example.com")
	base := filepath.Base(path)
	if !strings.HasSuffix(base, ".json") {
		t.Fatalf("cache path = %q, want .json suffix", path)
	}
	digest := strings.TrimSuffix(base, ".json")
	if len(digest) != 64 {
		t.Fatalf("digest length = %d, want full SHA-256 hex length 64", len(digest))
	}
}
